                          onClick={() => generatePreview(rule.id)}
                          style={{
                            background: "none", border: "1.5px solid #e5e7eb",
                            borderRadius: 10, padding: "8px 16px",
                            fontSize: 13, fontWeight: 600, cursor: "pointer",
